using UnityEngine;
public class ResultSystem : MonoBehaviour
{
    [SerializeField] private ShapeSystem shapeSystem;
    [SerializeField] private GlazeSystem glazeSystem;
    [SerializeField] private FiringSystem firingSystem;
    [SerializeField] private float shapeWeight = 1f;
    [SerializeField] private float glazeWeight = 1f;
    [SerializeField] private float fireWeight = 1f;
    private static readonly float[] GradeMultipliers =
    {
        0f,     // Defective 次品
        0.5f,   // Fair 良品
        1f,     // Good 佳品
        1.5f,   // Fine 精品
        2f      // Tribute 贡品
    };
    public ResultData GetResultData()
    {
        return new ResultData
        {
            ShapeMatch = shapeSystem != null ? shapeSystem.ShapeMatch : 0f,
            GlazeMatch = glazeSystem != null ? glazeSystem.GlazeMatch : 0f,
            FireScore = firingSystem != null ? firingSystem.GetFireScore() : 0f
        };
    }
    public ResultGrade GetResult()
    {
        ResultData data = GetResultData();
        float totalWeight = shapeWeight + glazeWeight + fireWeight;
        float totalScore = totalWeight > 0f
            ? (data.ShapeMatch * shapeWeight + data.GlazeMatch * glazeWeight + data.FireScore * fireWeight) / totalWeight
            : 0f;

        return new ResultGrade
        {
            TotalScore = totalScore,
            Grade = DetermineGrade(totalScore)
        };
    }
